Ghi sinh viên vào tệp nhị phân:

```c
void WriteFile(char *FileName) {
    FILE *f;
    int n, i;
    SinhVien sv;

    f = fopen(FileName, "wb");
    printf("Nhap bao nhieu sinh vien?");
    scanf("%d", &n);
    fflush(stdin);

    for (i = 1; i <= n; i++) {
        printf("Sinh vien thu %i\n", i);
        printf(" - MSSV: ");
        gets(sv.Ma);
        printf(" - Ho ten: ");
        gets(sv.HoTen);
        fwrite(&sv, sizeof(sv), 1, f);
        fflush(stdin);
    }

    fclose(f);
}
```

