```sql
DECLARE
 v_id number_table.id%TYPE := 100;
 v_num NUMBER:=1;
BEGIN
 LOOP
  INSERT INTO number_table(id,num)
  VALUES(v_id,v_num) ;
  v_num := v_num + 1;
  EXIT WHEN v_num > 10;
 END LOOP;
END;
